# ============================================================
# MODEL CODE (inline for self-contained app)
# ============================================================
cml_model_code <- '
$PARAM @annotated
ay0:0.008:HSC self-renewal rate
by0:0.004:HSC differentiation rate
dy0:0.003:HSC death rate
by1:0.05:CMP differentiation rate
dy1:0.02:CMP death rate
by2:0.2:GMP differentiation rate
dy2:0.05:GMP death rate
dy3:0.10:Neutrophil death rate
c1:10.0:HSC→CMP amplification
c2:8.0:CMP→GMP amplification
c3:16.0:GMP→Neutrophil amplification
a0:0.04:LSC self-renewal
b0:0.01:LSC differentiation
d0:0.003:LSC death
q_act:0.005:Quiescent LSC activation rate
q_dorm:0.02:LSC quiescence rate
a1:0.03:LPC1 self-renewal
b1:0.08:LPC1 differentiation
d1:0.015:LPC1 death
b2:0.15:LPC2 differentiation
d2:0.04:LPC2 death
d3:0.12:Leukemic blast death
lc1:15.0:LSC→LPC1 amplification
lc2:10.0:LPC1→LPC2 amplification
lc3:20.0:LPC2→WBC amplification
as0:0.035:Sensitive LSC self-renewal
bs0:0.012:Sensitive LSC differentiation
ds0:0.004:Sensitive LSC death
asp:0.04:Sensitive progenitor proliferation
dsp:0.02:Sensitive progenitor death
ar0:0.032:Resistant LSC self-renewal
br0:0.010:Resistant LSC differentiation
dr0:0.005:Resistant LSC death
arp:0.038:Resistant progenitor proliferation
drp:0.022:Resistant progenitor death
mu:1e-8:Mutation rate
ka_imt:0.8:Imatinib absorption rate
F_imt:0.98:Imatinib bioavailability
Vd_imt:435.0:Imatinib Vd (L)
CL_imt:14.0:Imatinib CL (L/h)
Kin_imt:0.5:OCT1 influx rate
Kout_imt:0.3:Intracellular efflux rate
IC50_imt:0.25:Imatinib IC50 (µM)
Emax_imt:0.90:Imatinib Emax
Hill_imt:1.2:Imatinib Hill coefficient
ka_das:3.5:Dasatinib absorption rate
F_das:0.24:Dasatinib bioavailability
Vd_das:2505.0:Dasatinib Vd (L)
CL_das:220.0:Dasatinib CL (L/h)
Kic_das:0.8:Dasatinib IC accumulation
Kout_das:0.4:Dasatinib IC efflux
IC50_das:0.025:Dasatinib IC50 (µM)
Emax_das:0.95:Dasatinib Emax
Hill_das:1.1:Dasatinib Hill
ka_nil:0.6:Nilotinib absorption rate
F_nil:0.35:Nilotinib bioavailability
Vd_nil:3100.0:Nilotinib Vd (L)
CL_nil:42.0:Nilotinib CL (L/h)
Kic_nil:0.6:Nilotinib IC accumulation
Kout_nil:0.35:Nilotinib IC efflux
IC50_nil:0.02:Nilotinib IC50 (µM)
Emax_nil:0.93:Nilotinib Emax
Hill_nil:1.15:Nilotinib Hill
ka_asc:1.2:Asciminib absorption rate
F_asc:0.72:Asciminib bioavailability
Vd_asc:95.0:Asciminib Vd (L)
CL_asc:7.5:Asciminib CL (L/h)
IC50_asc:0.0005:Asciminib IC50 (µM)
Emax_asc:0.90:Asciminib Emax
Hill_asc:1.3:Asciminib Hill
Kcomp:1e-9:Competition coefficient
kNK_kill:0.001:NK kill rate
kCTL_kill:0.0005:CTL kill rate
NK_base:1e8:Baseline NK count
CTL_base:5e7:Baseline CTL count
dose_imt:0:Imatinib dose (mg/day)
dose_das:0:Dasatinib dose (mg/day)
dose_nil:0:Nilotinib dose (mg/day)
dose_asc:0:Asciminib dose (mg/day)
risk_mult:1.0:Patient risk multiplier (Sokal)
OCT1_func:1.0:OCT1 functional activity (0-2)

$CMT y0 y1 y2 y3 x0q x0p x1 x2 x3 xs xsp xr xrp
     Gut_imt Cp_imt Cic_imt Cp_das Cic_das
     Gut_nil Cp_nil Cic_nil Gut_asc Cp_asc

$INIT
y0=1e4 y1=5e4 y2=4e5 y3=4e9
x0q=1e4 x0p=2e3 x1=1e7 x2=5e7 x3=5e10
xs=8e3 xsp=8e6 xr=10 xrp=100
Gut_imt=0 Cp_imt=0 Cic_imt=0
Cp_das=0 Cic_das=0
Gut_nil=0 Cp_nil=0 Cic_nil=0
Gut_asc=0 Cp_asc=0

$ODE
double dose_rate_imt = dose_imt / 24.0 / 493.6 * 1000.0;
double dose_rate_das = dose_das / 24.0 / 488.0 * 1000.0;
double dose_rate_nil = dose_nil / 24.0 / 529.5 * 1000.0;
double dose_rate_asc = dose_asc / 24.0 / 449.5 * 1000.0;

dxdt_Gut_imt = F_imt * dose_rate_imt - ka_imt * Gut_imt;
dxdt_Cp_imt  = ka_imt * Gut_imt / Vd_imt - (CL_imt / Vd_imt) * Cp_imt;
dxdt_Cic_imt = OCT1_func * Kin_imt * Cp_imt - Kout_imt * Cic_imt;

dxdt_Cp_das  = F_das * dose_rate_das / Vd_das - (CL_das / Vd_das) * Cp_das;
dxdt_Cic_das = Kic_das * Cp_das - Kout_das * Cic_das;

dxdt_Gut_nil = F_nil * dose_rate_nil - ka_nil * Gut_nil;
dxdt_Cp_nil  = ka_nil * Gut_nil / Vd_nil - (CL_nil / Vd_nil) * Cp_nil;
dxdt_Cic_nil = Kic_nil * Cp_nil - Kout_nil * Cic_nil;

dxdt_Gut_asc = F_asc * dose_rate_asc - ka_asc * Gut_asc;
dxdt_Cp_asc  = ka_asc * Gut_asc / Vd_asc - (CL_asc / Vd_asc) * Cp_asc;

double Cimt_eff = fmax(Cic_imt, 0.0);
double E_imt = Emax_imt * pow(Cimt_eff, Hill_imt) /
               (pow(IC50_imt, Hill_imt) + pow(Cimt_eff, Hill_imt) + 1e-15);
double Cdas_eff = fmax(Cic_das, 0.0);
double E_das = Emax_das * pow(Cdas_eff, Hill_das) /
               (pow(IC50_das, Hill_das) + pow(Cdas_eff, Hill_das) + 1e-15);
double Cnil_eff = fmax(Cic_nil, 0.0);
double E_nil = Emax_nil * pow(Cnil_eff, Hill_nil) /
               (pow(IC50_nil, Hill_nil) + pow(Cnil_eff, Hill_nil) + 1e-15);
double Casc_eff = fmax(Cp_asc, 0.0);
double E_asc = Emax_asc * pow(Casc_eff, Hill_asc) /
               (pow(IC50_asc, Hill_asc) + pow(Casc_eff, Hill_asc) + 1e-15);

double E_total_sens = fmin(0.98, E_imt + E_das + E_nil + E_asc);

double Ntotal = x0q + x0p + x1 + x2 + x3 + xs + xsp + xr + xrp +
                y0 + y1 + y2 + y3;
double suppress = fmax(0.0, 1.0 - Kcomp * Ntotal);

dxdt_y0 = ay0 * y0 - by0 * y0 - dy0 * y0;
dxdt_y1 = c1 * by0 * y0 - by1 * y1 - dy1 * y1;
dxdt_y2 = c2 * by1 * y1 - by2 * y2 - dy2 * y2;
dxdt_y3 = c3 * by2 * y2 - dy3 * y3;

double q_in  = q_dorm * x0p;
double q_out = q_act  * x0q;
double NK_kill_x0q = kNK_kill * NK_base * x0q / (x0q + 1e3 + 1e-15);

dxdt_x0q = q_in - q_out - d0 * x0q - NK_kill_x0q;
dxdt_x0p = a0 * risk_mult * x0p + q_out - q_in - b0 * x0p - d0 * x0p
           - E_total_sens * x0p
           - kNK_kill * NK_base * x0p / (x0p + 1e3 + 1e-15)
           + mu * a0 * xs;
dxdt_x1  = lc1 * b0 * x0p - b1 * x1 - d1 * x1 - E_total_sens * x1 * 0.6;
dxdt_x2  = lc2 * b1 * x1 - b2 * x2 - d2 * x2 - E_total_sens * x2 * 0.8;
dxdt_x3  = lc3 * b2 * x2 - d3 * x3 - E_total_sens * x3
           - kNK_kill * NK_base * x3 / (x3 + 1e8 + 1e-15)
           - kCTL_kill * CTL_base * x3 / (x3 + 1e8 + 1e-15);

double TKI_kill_xs = E_total_sens * xs;
dxdt_xs  = as0 * xs - bs0 * xs - ds0 * xs - TKI_kill_xs - mu * as0 * xs;
dxdt_xsp = lc1 * bs0 * xs + asp * xsp - dsp * xsp - E_total_sens * xsp * 0.7;

dxdt_xr  = ar0 * xr - br0 * xr - dr0 * xr;
dxdt_xrp = lc1 * br0 * xr + arp * xrp - drp * xrp;

$TABLE
double CML_total = x3 + xrp + xsp;
double Norm_total = y3;
double BCRPCT = 100.0 * CML_total / fmax(CML_total + Norm_total, 1.0);
double LOG_IS = (BCRPCT > 0.0001) ? log10(BCRPCT) : -5.0;

capture BCRPCT = BCRPCT;
capture LOG_IS = LOG_IS;
capture CHR = (BCRPCT < 10.0) ? 1.0 : 0.0;
capture MMR = (BCRPCT < 0.1) ? 1.0 : 0.0;
capture MR4 = (BCRPCT < 0.01) ? 1.0 : 0.0;
capture MR45 = (BCRPCT < 0.0032) ? 1.0 : 0.0;
capture WBC_total = (x3 + Norm_total) / 5e9;
capture LSC_quies_frac = x0q / fmax(x0q + x0p + xs, 1.0);
capture Resist_frac = (xr + xrp) / fmax(CML_total, 1.0);
capture Cp_imt_out = Cp_imt;
capture Cic_imt_out = Cic_imt;
capture Cp_das_out = Cp_das;
capture Cic_das_out = Cic_das;
capture Cp_nil_out = Cp_nil;
capture Cic_nil_out = Cic_nil;
capture Cp_asc_out = Cp_asc;
capture x0q_out = x0q;
capture x0p_out = x0p;
capture x3_out = x3;
capture y3_out = y3;
capture xr_out = xr;
capture xs_out = xs;
'

# ============================================================
# Compile model (once at startup)
# ============================================================
mod <- mcode("cml_shiny", cml_model_code)

# ============================================================
# Helper functions
# ============================================================
to_months <- function(t_hr) t_hr / (365.25 * 24 / 12)

run_sim <- function(mod, drug, dose, years = 5, risk_mult = 1.0, oct1 = 1.0, mu_rate = 1e-8) {
  t_end <- years * 365.25 * 24
  dt    <- 24
  times <- seq(0, t_end, by = dt)

  dose_params <- list(dose_imt = 0, dose_das = 0, dose_nil = 0, dose_asc = 0,
                      risk_mult = risk_mult, OCT1_func = oct1, mu = mu_rate)
  dose_params[[paste0("dose_", drug)]] <- dose

  mod %>%
    param(dose_params) %>%
    mrgsim(end = t_end, delta = dt) %>%
    as.data.frame() %>%
    mutate(time_months = to_months(time))
}

sokal_score <- function(age, spleen_cm, plt, blast_pct) {
  # Sokal 1984 formula
  score <- exp(0.0116 * (age - 43.4) +
               0.0345 * (spleen_cm - 7.51) +
               0.188  * ((plt / 700)^2 - 0.563) +
               0.0887 * (blast_pct - 2.10))
  risk <- ifelse(score < 0.8, "Low", ifelse(score < 1.2, "Intermediate", "High"))
  list(score = round(score, 3), risk = risk)
}

eutos_score <- function(spleen_cm, baso_pct) {
  # EUTOS 2011 formula
  score <- 7 * baso_pct + 4 * spleen_cm
  risk  <- ifelse(score <= 87, "Low", "High")
  list(score = round(score, 1), risk = risk)
}

