                        min = -10, max = -5, value = -8, step = 0.5),
            sliderInput("tfr_threshold", "TFR 시작 기준 (MR):",
                        min = 3, max = 4.5, value = 4.0, step = 0.5),
            sliderInput("tfr_duration_yr", "TFR 전 지속 기간 (년):",
                        min = 1, max = 5, value = 2, step = 0.5),
            actionButton("run_tfr", "TFR 시뮬레이션 실행",
                         class = "btn-danger btn-block")
          )
        ),
        fluidRow(
          box(title = "TFR 성공 예측 (TKI 중단 후 BCR-ABL IS%)", width = 8,
              status = "primary",
            plotlyOutput("tfr_plot", height = "350px")
          ),
          box(title = "TFR 성공 예측 인자", width = 4, status = "success",
            h4("긍정적 예측인자"),
            tags$ul(
              tags$li("MR4.5 지속 ≥ 2년"),
              tags$li("높은 NK 세포 활성도"),
              tags$li("치료 기간 ≥ 5년"),
              tags$li("ENESTfreedom: 2세대 TKI")
            ),
            hr(),
            h4("부정적 예측인자"),
            tags$ul(
              tags$li("High Sokal 위험군"),
              tags$li("이전 AP/BC 병기"),
              tags$li("짧은 DMR 지속 기간"),
              tags$li("잔류 LSC 정지기 클론")
            ),
            hr(),
            verbatimTextOutput("tfr_probability")
          )
        ),
        fluidRow(
          box(title = "돌연변이별 TKI 내성 프로파일", width = 12, status = "info",
            tableOutput("mutation_table")
          )
        )
      )
    )  # end tabItems
  )  # end dashboardBody
)  # end dashboardPage

# ============================================================
# SERVER
# ============================================================
server <- function(input, output, session) {

  # Reactive simulation result
  sim_result <- eventReactive(input$run_sim, {
    withProgress(message = "시뮬레이션 실행 중...", {
      drug <- input$drug
      dose_val <- switch(drug,
                         imt = input$dose_imt %||% 400,
                         das = input$dose_das %||% 100,
                         nil = input$dose_nil %||% 600,
                         asc = input$dose_asc %||% 80)

      dose_params <- list(dose_imt = 0, dose_das = 0,
                          dose_nil = 0, dose_asc = 0,
                          risk_mult = input$risk_mult,
                          OCT1_func = input$oct1_func,
                          mu        = 1e-8)
      dose_params[[paste0("dose_", drug)]] <- dose_val

      t_end <- input$sim_years * 365.25 * 24
      mod %>%
        param(dose_params) %>%
        mrgsim(end = t_end, delta = 24) %>%
        as.data.frame() %>%
        mutate(time_months = to_months(time))
    })
  }, ignoreNULL = FALSE)

  # Initial simulation on load (imatinib default)
  observe({
    input$run_sim
  })

  # Dynamic dose UI
  output$dose_ui <- renderUI({
    drug <- input$drug
    switch(drug,
      imt = sliderInput("dose_imt", "이마티닙 용량 (mg/day):",
                        min = 200, max = 800, value = 400, step = 100),
      das = sliderInput("dose_das", "다사티닙 용량 (mg/day):",
                        min = 50, max = 140, value = 100, step = 10),
      nil = sliderInput("dose_nil", "닐로티닙 용량 (mg/day):",
                        min = 300, max = 900, value = 600, step = 150),
      asc = sliderInput("dose_asc", "아시미닙 용량 (mg/day):",
                        min = 40, max = 400, value = 80, step = 40)
    )
  })

  # --------------------------------------------------------
  # TAB 1: Patient Profile
  # --------------------------------------------------------
  output$sokal_out <- renderPrint({
    req(input$calc_score)
    s <- sokal_score(input$pt_age, input$pt_spleen, input$pt_plt, input$pt_blast)
    cat("Sokal 점수:", s$score, "\n위험군:", s$risk, "\n")
  })

  output$eutos_out <- renderPrint({
    req(input$calc_score)
    e <- eutos_score(input$pt_spleen, input$pt_baso)
    cat("EUTOS 점수:", e$score, "\n위험군:", e$risk, "\n")
  })

  output$eln_rec <- renderPrint({
    req(input$calc_score)
    s <- sokal_score(input$pt_age, input$pt_spleen, input$pt_plt, input$pt_blast)
    if (s$risk == "Low") {
      cat("권고: Imatinib 400mg 또는 2세대 TKI\n(TFR 목표 가능)")
    } else if (s$risk == "Intermediate") {
      cat("권고: 2세대 TKI (dasatinib/nilotinib)\n(조기 깊은 분자반응 목표)")
    } else {
      cat("권고: 2세대 또는 Ponatinib 고려\n(철저한 추적 관찰 필요)")
    }
  })

  output$patient_summary <- renderTable({
    data.frame(
      항목 = c("나이", "비장 크기", "혈소판", "아세포", "진단 BCR-ABL"),
      값   = c(paste0(input$pt_age, "세"),
               paste0(input$pt_spleen, " cm"),
               paste0(input$pt_plt, " ×10⁹/L"),
               paste0(input$pt_blast, "%"),
               paste0(input$pt_bcrabl, "% IS"))
    )
  })

  # --------------------------------------------------------
  # TAB 2: PK Profiles
  # --------------------------------------------------------
  output$pk_plasma_plot <- renderPlotly({
    df <- sim_result()
    req(df)
    drug <- input$drug

    pk_col <- switch(drug,
                     imt = "Cp_imt_out", das = "Cp_das_out",
                     nil = "Cp_nil_out", asc = "Cp_asc_out")

    df_pk <- df %>% filter(time_months <= 1) %>%
      mutate(time_h = time_months * 30 * 24,
             Cp = .data[[pk_col]])

    p <- ggplot(df_pk, aes(x = time_h, y = Cp)) +
      geom_line(color = "#377EB8", size = 1.2) +
      labs(title = paste("혈장 농도:", drug_info$name[drug_info$drug == drug]),
           x = "시간 (h)", y = "농도 (µM)") +
      theme_bw(base_size = 12)
    ggplotly(p)
  })

  output$pk_ic_plot <- renderPlotly({
    df <- sim_result()
    req(df)
    drug <- input$drug

    ic_col <- switch(drug,
                     imt = "Cic_imt_out", das = "Cic_das_out",
                     nil = "Cic_nil_out", asc = "Cp_asc_out")

    df_ic <- df %>% filter(time_months <= 3) %>%
      mutate(time_h = time_months * 30 * 24,
             Cic = .data[[ic_col]])

    p <- ggplot(df_ic, aes(x = time_h, y = Cic)) +
      geom_line(color = "#E41A1C", size = 1.2) +
      labs(title = "세포내 농도 (Intracellular)",
           x = "시간 (h)", y = "농도 (µM)") +
      theme_bw(base_size = 12)
    ggplotly(p)
  })

  output$pk_params_table <- renderTable({
    drug <- input$drug
    info <- drug_info[drug_info$drug == drug, ]
    data.frame(
      파라미터 = c("약물", "세대", "표준 용량", "생체이용률", "반감기"),
      값 = c(info$name, info$generation, info$label,
             switch(drug, imt="98%", das="24%", nil="35%", asc="72%"),
             switch(drug, imt="18h", das="5-6h", nil="17h", asc="8.7h"))
    )
  })

  output$pk_summary_table <- renderTable({
    drug <- input$drug
    data.frame(
      TKI      = c("Imatinib", "Dasatinib", "Nilotinib", "Asciminib"),
      용량     = c("400mg/day", "100mg/day", "300mg BID", "40mg BID"),
      IC50_µM  = c("0.25", "0.025", "0.020", "0.0005"),
      생체이용률= c("98%", "14-34%", "30-40%", "~72%"),
      t1_2     = c("18h", "5-6h", "17h", "8.7h"),
      주요_작용 = c("DFG-out", "DFG-in (Src)", "DFG-in", "STAMP/myristoyl"),
      T315I    = c("내성", "내성", "내성", "부분 감수성\n(200mg BID)")
    )
  })

  # --------------------------------------------------------
  # TAB 3: Molecular Response
  # --------------------------------------------------------
  output$bcrabl_plot <- renderPlotly({
    df <- sim_result()
    req(df)

    # Reference lines data
    milestones <- data.frame(
      y    = c(0.1, 0.01, 0.0032, 10),
      label = c("MMR (0.1%)", "MR4 (0.01%)", "MR4.5 (0.0032%)", "CHR (<10%)"),
      color = c("blue", "purple", "darkgreen", "orange")
    )

    p <- ggplot(df, aes(x = time_months, y = BCRPCT)) +
      geom_line(color = "#E41A1C", size = 1.4) +
      scale_y_log10(
        breaks = c(100, 10, 1, 0.1, 0.01, 0.001),
        labels = c("100%", "10%", "1%", "0.1%", "0.01%", "0.001%")
      ) +
      geom_hline(yintercept = 0.1,    linetype = "dashed", color = "blue",      size = 0.8) +
      geom_hline(yintercept = 0.01,   linetype = "dashed", color = "purple",    size = 0.8) +
      geom_hline(yintercept = 0.0032, linetype = "dashed", color = "darkgreen", size = 0.8) +
      geom_hline(yintercept = 10,     linetype = "dashed", color = "orange",    size = 0.8) +
      geom_vline(xintercept = c(3, 6, 12, 18, 24, 36, 48),
                 linetype = "dotted", alpha = 0.5) +
      annotate("text", x = max(df$time_months) * 0.6, y = 0.12,
               label = "MMR", color = "blue", size = 3.5) +
      annotate("text", x = max(df$time_months) * 0.6, y = 0.012,
               label = "MR4", color = "purple", size = 3.5) +
      annotate("text", x = max(df$time_months) * 0.6, y = 0.004,
               label = "MR4.5", color = "darkgreen", size = 3.5) +
      labs(
        title = "BCR-ABL IS% — 분자반응 프로파일",
        x = "치료 기간 (개월)", y = "BCR-ABL IS% (log 스케일)"
      ) +
      theme_bw(base_size = 12)
    ggplotly(p)
  })

  # Response milestones
  get_milestone_time <- function(df, threshold) {
    idx <- which(df$BCRPCT <= threshold)[1]
    if (is.na(idx)) return(NA) else return(df$time_months[idx])
  }

  output$vbox_CHR <- renderValueBox({
    df <- sim_result()
    t  <- get_milestone_time(df, 10)
    valueBox(
      value = if (is.na(t)) "미달성" else paste0(round(t, 0), "개월"),
      subtitle = "CHR 달성 (IS% <10%)",
      icon  = icon("check-circle"),
      color = if (is.na(t)) "red" else "green"
    )
  })

  output$vbox_CCyR <- renderValueBox({
    df <- sim_result()
    t  <- get_milestone_time(df, 1)
    valueBox(
      value = if (is.na(t)) "미달성" else paste0(round(t, 0), "개월"),
      subtitle = "CCyR (IS% <1%)",
      icon  = icon("check-circle"),
      color = if (is.na(t)) "red" else "blue"
    )
  })

  output$vbox_MMR <- renderValueBox({
    df <- sim_result()
    t  <- get_milestone_time(df, 0.1)
    valueBox(
      value = if (is.na(t)) "미달성" else paste0(round(t, 0), "개월"),
      subtitle = "MMR 달성 (IS% ≤0.1%)",
      icon  = icon("star"),
      color = if (is.na(t)) "orange" else "purple"
    )
  })

  output$vbox_MR45 <- renderValueBox({
    df <- sim_result()
    t  <- get_milestone_time(df, 0.0032)
    valueBox(
      value = if (is.na(t)) "미달성" else paste0(round(t, 0), "개월"),
      subtitle = "MR4.5 (TFR 기준)",
      icon  = icon("trophy"),
      color = if (is.na(t)) "orange" else "yellow"
    )
  })

  milestone_status_ui <- function(achieved, label, detail) {
    cls <- if (achieved) "milestone-achieved" else "milestone-pending"
    icon_txt <- if (achieved) "✓" else "✗"
    div(class = paste("milestone-box", cls),
        paste(icon_txt, label, "|", detail))
  }

  output$milestone_3mo <- renderUI({
    df <- sim_result()
    val_3 <- df$BCRPCT[df$time_months >= 3][1]
    tagList(
      milestone_status_ui(!is.na(val_3) && val_3 < 10,
                          "BCR-ABL <10%", paste0(round(val_3, 2), "%")),
      milestone_status_ui(!is.na(val_3) && val_3 < 1,
                          "BCR-ABL <1%", "(최적 반응)")
    )
  })

  output$milestone_6mo <- renderUI({
    df <- sim_result()
    val_6 <- df$BCRPCT[df$time_months >= 6][1]
    tagList(
      milestone_status_ui(!is.na(val_6) && val_6 < 10,
                          "BCR-ABL <10%", paste0(round(val_6, 2), "%")),
      milestone_status_ui(!is.na(val_6) && val_6 < 1,
                          "BCR-ABL <1%", "CCyR 방향")
    )
  })

  output$milestone_12mo <- renderUI({
    df <- sim_result()
    val_12 <- df$BCRPCT[df$time_months >= 12][1]
    tagList(
      milestone_status_ui(!is.na(val_12) && val_12 < 1,
                          "CCyR (BCR-ABL <1%)", paste0(round(val_12, 3), "%")),
      milestone_status_ui(!is.na(val_12) && val_12 < 0.1,
                          "MMR (BCR-ABL ≤0.1%)", "12개월 조기 달성")
    )
  })

  output$milestone_18mo <- renderUI({
    df <- sim_result()
    val_18 <- df$BCRPCT[df$time_months >= 18][1]
    tagList(
      milestone_status_ui(!is.na(val_18) && val_18 < 0.1,
                          "MMR 유지", paste0(round(val_18, 4), "%")),
      milestone_status_ui(!is.na(val_18) && val_18 < 0.01,
                          "MR4 달성", "Deep remission")
    )
  })

  output$response_time_table <- renderTable({
    df <- sim_result()
    data.frame(
      반응지표   = c("CHR (IS% <10%)", "CCyR (IS% <1%)", "MMR (IS% ≤0.1%)",
                     "MR4 (IS% ≤0.01%)", "MR4.5 (IS% ≤0.0032%)"),
      임계값     = c("10%", "1%", "0.1%", "0.01%", "0.0032%"),
      달성_개월  = c(
        ifelse(is.na(get_milestone_time(df, 10)),    "미달성", paste0(round(get_milestone_time(df, 10), 0), "개월")),
        ifelse(is.na(get_milestone_time(df, 1)),     "미달성", paste0(round(get_milestone_time(df, 1),  0), "개월")),
        ifelse(is.na(get_milestone_time(df, 0.1)),   "미달성", paste0(round(get_milestone_time(df, 0.1),0), "개월")),
        ifelse(is.na(get_milestone_time(df, 0.01)),  "미달성", paste0(round(get_milestone_time(df, 0.01), 0), "개월")),
        ifelse(is.na(get_milestone_time(df, 0.0032)),"미달성", paste0(round(get_milestone_time(df, 0.0032), 0), "개월"))
      ),
      ELN_2020_기준 = c("3개월내 권고", "12개월내 최적", "18개월내 목표", "심층반응", "TFR 전제조건")
    )
  })

  # --------------------------------------------------------
  # TAB 4: Cell Kinetics
  # --------------------------------------------------------
  output$leuk_cells_plot <- renderPlotly({
    df <- sim_result()
    req(df)

    df_cells <- df %>%
      select(time_months, x0q_out, x0p_out, x1, x2, x3_out) %>%
      pivot_longer(-time_months, names_to = "pop", values_to = "count") %>%
      mutate(
        population = case_when(
          pop == "x0q_out" ~ "LSC 정지기 (x0q)",
          pop == "x0p_out" ~ "LSC 증식기 (x0p)",
          pop == "x1"      ~ "LPC1 (x1)",
          pop == "x2"      ~ "LPC2 (x2)",
          pop == "x3_out"  ~ "백혈병 WBC (x3)"
        ),
        count = pmax(count, 1)
      )

    p <- ggplot(df_cells, aes(x = time_months, y = count,
                              color = population)) +
      geom_line(size = 1.1) +
      scale_y_log10() +
      scale_color_brewer(palette = "Set1") +
      labs(title = "CML 세포 집단 역학 (로그 스케일)",
           x = "시간 (개월)", y = "세포 수 (log10)",
           color = "세포 집단") +
      theme_bw(base_size = 12)
    ggplotly(p)
  })

  output$normal_cells_plot <- renderPlotly({
    df <- sim_result()
    req(df)

    df_norm <- df %>%
      select(time_months, y0, y1, y2, y3_out) %>%
      pivot_longer(-time_months, names_to = "pop", values_to = "count") %>%
      mutate(
        population = case_when(
          pop == "y0"     ~ "HSC (y0)",
          pop == "y1"     ~ "CMP (y1)",
          pop == "y2"     ~ "GMP (y2)",
          pop == "y3_out" ~ "정상 WBC (y3)"
        ),
        count = pmax(count, 1)
      )

    p <- ggplot(df_norm, aes(x = time_months, y = count, color = population)) +
      geom_line(size = 1.1) +
      scale_y_log10() +
      scale_color_brewer(palette = "Set2") +
      labs(title = "정상 조혈 세포",
           x = "시간 (개월)", y = "세포 수 (log10)",
           color = "세포 집단") +
      theme_bw(base_size = 12)
    ggplotly(p)
  })

  output$lsc_plot <- renderPlotly({
    df <- sim_result()
    req(df)

    p <- ggplot(df, aes(x = time_months)) +
      geom_line(aes(y = x0q_out, color = "LSC 정지기"), size = 1.1) +
      geom_line(aes(y = x0p_out, color = "LSC 증식기"), size = 1.1) +
      geom_line(aes(y = LSC_quies_frac * 1e5, color = "정지기 분율 (×10⁵)"),
                size = 1.0, linetype = "dashed") +
      scale_y_log10() +
      scale_color_manual(values = c("LSC 정지기" = "#E41A1C",
                                    "LSC 증식기" = "#377EB8",
                                    "정지기 분율 (×10⁵)" = "#4DAF4A")) +
      labs(title = "LSC 정지기/증식기 역학",
           x = "시간 (개월)", y = "세포 수 (log10)",
           color = "") +
      theme_bw(base_size = 12)
    ggplotly(p)
  })

  output$clone_plot <- renderPlotly({
    df <- sim_result()
    req(df)

    p <- ggplot(df, aes(x = time_months)) +
      geom_line(aes(y = xs_out + 1, color = "민감 LSC 클론 (xs)"), size = 1.1) +
      geom_line(aes(y = xr_out + 1, color = "T315I 내성 클론 (xr)"), size = 1.1) +
      scale_y_log10() +
      scale_color_manual(values = c("민감 LSC 클론 (xs)" = "#4DAF4A",
                                    "T315I 내성 클론 (xr)" = "#E41A1C")) +
      labs(title = "민감/내성 클론 역학",
           x = "시간 (개월)", y = "세포 수 (log10)",
           color = "") +
      theme_bw(base_size = 12)
    ggplotly(p)
  })

  # --------------------------------------------------------
  # TAB 5: Scenario Comparison
  # --------------------------------------------------------
  compare_result <- eventReactive(input$run_compare, {
    withProgress(message = "비교 시뮬레이션 실행 중...", {
      drugs <- input$compare_drugs
      doses <- c(imt = 400, das = 100, nil = 600, asc = 80)

      results <- lapply(drugs, function(d) {
        dose_params <- list(dose_imt = 0, dose_das = 0,
                            dose_nil = 0, dose_asc = 0,
                            risk_mult = input$risk_mult,
                            OCT1_func = input$oct1_func)
        dose_params[[paste0("dose_", d)]] <- doses[d]

        t_end <- input$sim_years * 365.25 * 24
        mod %>%
          param(dose_params) %>%
          mrgsim(end = t_end, delta = 24) %>%
          as.data.frame() %>%
          mutate(time_months = to_months(time),
                 drug_label  = drug_info$label[drug_info$drug == d])
      })
      bind_rows(results)
    })
  })

  output$compare_plot <- renderPlotly({
    df <- compare_result()
    req(df)

    colors <- setNames(drug_info$color, drug_info$label)

    p <- ggplot(df, aes(x = time_months, y = BCRPCT,
                        color = drug_label)) +
      geom_line(size = 1.2) +
      scale_y_log10(
        breaks = c(100, 10, 1, 0.1, 0.01, 0.001),
        labels = c("100%", "10%", "1%", "MMR 0.1%", "MR4 0.01%", "MR4.5 0.001%")
      ) +
      geom_hline(yintercept = c(0.1, 0.01, 0.0032),
                 linetype = "dashed", alpha = 0.6) +
      scale_color_manual(values = colors, na.value = "#999999") +
      labs(
        title = "TKI 시나리오 비교 — BCR-ABL IS%",
        subtitle = "ELN 2020 기준 분자반응 비교",
        x = "치료 기간 (개월)", y = "BCR-ABL IS% (log 스케일)",
        color = "치료약제"
      ) +
      theme_bw(base_size = 12) +
      theme(legend.position = "right")
    ggplotly(p)
  })

  output$compare_milestone_table <- renderTable({
    df <- compare_result()
    req(df)

    thresholds <- c(CHR = 10, CCyR = 1, MMR = 0.1, MR4 = 0.01, MR45 = 0.0032)
    drugs_sel  <- unique(df$drug_label)

    rows <- lapply(drugs_sel, function(d) {
      sub_df <- df[df$drug_label == d, ]
      times  <- sapply(thresholds, function(thr) {
        idx <- which(sub_df$BCRPCT <= thr)[1]
        if (is.na(idx)) "미달성" else paste0(round(sub_df$time_months[idx], 0), "개월")
      })
      c(TKI = d, times)
    })

    do.call(rbind, lapply(rows, as.data.frame, stringsAsFactors = FALSE))
  })

  # --------------------------------------------------------
  # TAB 6: Resistance & TFR
  # --------------------------------------------------------
  output$resist_plot <- renderPlotly({
    df <- sim_result()
    req(df)

    mu_rate <- 10^input$mu_rate_exp

    dose_params <- list(dose_imt = 400, dose_das = 0,
                        dose_nil = 0, dose_asc = 0,
                        mu = mu_rate,
                        risk_mult = input$risk_mult)

    t_end <- input$sim_years * 365.25 * 24
    df_r  <- mod %>%
      param(dose_params) %>%
      mrgsim(end = t_end, delta = 24) %>%
      as.data.frame() %>%
      mutate(time_months = to_months(time))

    p <- ggplot(df_r, aes(x = time_months)) +
      geom_line(aes(y = BCRPCT, color = "BCR-ABL IS% (전체)"), size = 1.2) +
      geom_line(aes(y = Resist_frac * 100, color = "T315I 클론 분율 (%)"),
                size = 1.1, linetype = "dashed") +
      scale_y_log10() +
      scale_color_manual(values = c("BCR-ABL IS% (전체)" = "#E41A1C",
                                    "T315I 클론 분율 (%)" = "#9966CC")) +
      geom_hline(yintercept = 0.1, linetype = "dashed", color = "blue", alpha = 0.7) +
      labs(
        title = paste0("이마티닙 치료 중 T315I 내성 출현\n(돌연변이율: 10^", input$mu_rate_exp, ")"),
        x = "치료 기간 (개월)",
        y = "% (log 스케일)", color = ""
      ) +
      theme_bw(base_size = 12)
    ggplotly(p)
  })

  tfr_result <- eventReactive(input$run_tfr, {
    withProgress(message = "TFR 시뮬레이션 실행 중...", {
      drug   <- input$drug
      doses  <- c(imt = 400, das = 100, nil = 600, asc = 80)
      t_pre  <- input$tfr_duration_yr * 365.25 * 24  # pre-TFR treatment
      t_post <- 3 * 365.25 * 24   # 3 years post-TFR

      dose_params <- list(dose_imt = 0, dose_das = 0,
                          dose_nil = 0, dose_asc = 0,
                          risk_mult = input$risk_mult)
      dose_params[[paste0("dose_", drug)]] <- doses[drug]

      # Pre-TFR phase
      pre_df <- mod %>%
        param(dose_params) %>%
        mrgsim(end = t_pre, delta = 24) %>%
        as.data.frame()

      # Extract end-state
      es <- tail(pre_df, 1)
      init_off <- c(
        y0 = es$y0, y1 = es$y1, y2 = es$y2, y3 = es$y3,
        x0q = es$x0q, x0p = es$x0p, x1 = es$x1, x2 = es$x2, x3 = es$x3,
        xs = es$xs, xsp = es$xsp, xr = es$xr, xrp = es$xrp,
        Gut_imt = 0, Cp_imt = 0, Cic_imt = 0,
        Cp_das = 0, Cic_das = 0,
        Gut_nil = 0, Cp_nil = 0, Cic_nil = 0,
        Gut_asc = 0, Cp_asc = 0
      )

      # Post-TFR (off treatment)
      post_df <- mod %>%
        param(dose_imt = 0, dose_das = 0, dose_nil = 0, dose_asc = 0,
              risk_mult = input$risk_mult) %>%
        init(init_off) %>%
        mrgsim(end = t_post, delta = 24) %>%
        as.data.frame() %>%
        mutate(time_months = to_months(time) + input$tfr_duration_yr * 12)

      pre_df2 <- pre_df %>%
        mutate(time_months = to_months(time),
               phase = "TKI 치료기")
      post_df$phase <- "TFR (약물 중단)"

      list(
        combined = bind_rows(pre_df2, post_df),
        pre_IS = tail(pre_df$BCRPCT, 1),
        post_6mo_IS = post_df$BCRPCT[post_df$time_months >= input$tfr_duration_yr * 12 + 6][1]
      )
    })
  })

  output$tfr_plot <- renderPlotly({
    res <- tfr_result()
    req(res)

    vline_x <- input$tfr_duration_yr * 12

    p <- ggplot(res$combined, aes(x = time_months, y = BCRPCT + 0.0001, color = phase)) +
      geom_line(size = 1.3) +
      scale_y_log10(
        breaks = c(100, 10, 1, 0.1, 0.01, 0.001, 0.0001),
        labels = c("100%", "10%", "1%", "0.1%", "0.01%", "0.001%", "0.0001%")
      ) +
      geom_vline(xintercept = vline_x, linetype = "longdash",
                 color = "red", size = 1.2) +
      geom_hline(yintercept = 0.1, linetype = "dashed", color = "blue", alpha = 0.7) +
      annotate("text", x = vline_x + 1, y = 50, label = "TKI 중단",
               color = "red", hjust = 0, size = 4) +
      scale_color_manual(values = c("TKI 치료기" = "#377EB8",
                                    "TFR (약물 중단)" = "#E41A1C")) +
      labs(
        title = "TFR 시뮬레이션 — TKI 중단 후 BCR-ABL IS%",
        x = "시간 (개월)", y = "BCR-ABL IS% (log 스케일)", color = ""
      ) +
      theme_bw(base_size = 12)
    ggplotly(p)
  })

  output$tfr_probability <- renderPrint({
    res <- tfr_result()
    req(res)

    pre_IS    <- res$pre_IS
    post_6mo  <- res$post_6mo_IS

    cat("=== TFR 시뮬레이션 결과 ===\n")
    cat("TKI 중단 시 BCR-ABL IS%:", round(pre_IS, 5), "%\n")
    if (!is.na(post_6mo)) {
      cat("중단 후 6개월 BCR-ABL IS%:", round(post_6mo, 4), "%\n")
      if (post_6mo < 0.1) {
        cat("예측: TFR 유지 (분자적 관해 지속)\n")
        cat("성공 확률 추정: ~45-55%\n")
      } else {
        cat("예측: 분자적 재발 (MMR 손실)\n")
        cat("재치료 권고: 이전 TKI 재개\n")
        cat("재치료 반응률: >90%\n")
      }
    }
    cat("\n임상 근거 (EURO-SKI):\n")
    cat("  - MR4.5 지속 ≥ 2년: TFR 성공 43-50%\n")
    cat("  - 1세대 TKI (STIM): 38%\n")
    cat("  - 2세대 TKI (ENESTfreedom): 51%\n")
    cat("  - NK 활성도 높을수록 성공률 ↑\n")
  })

  output$mutation_table <- renderTable({
    data.frame(
      돌연변이   = c("T315I (gatekeeper)", "E255K (P-loop)", "Y253H (P-loop)",
                     "F317L (SH2 접촉)", "T315A", "E459K (myristoyl pocket)"),
      위치       = c("315", "255", "253", "317", "315", "459"),
      이마티닙   = c("내성", "내성", "내성", "감수성", "내성", "감수성"),
      다사티닙   = c("내성", "내성", "내성", "내성", "감수성", "감수성"),
      닐로티닙   = c("내성", "내성", "내성", "감수성", "감수성", "감수성"),
      포나티닙   = c("감수성", "감수성", "감수성", "감수성", "감수성", "감수성"),
      아시미닙_40mg  = c("내성", "감수성", "감수성", "감수성", "감수성", "내성"),
      아시미닙_200mg = c("감수성", "감수성", "감수성", "감수성", "감수성", "내성"),
      발생_빈도  = c("~15%", "~7%", "~7%", "~5%", "~3%", "~2%")
    )
  })

}  # end server

# ============================================================
# Null-coalescing helper
# ============================================================
`%||%` <- function(a, b) if (is.null(a)) b else a

# ============================================================
# Run the app
# ============================================================
shinyApp(ui = ui, server = server)
